s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

BUCKET_NAME = os.environ.get('BUCKET_NAME', 'microservices-data')
TABLE_NAME = os.environ.get('TABLE_NAME', 'microservices-items')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', '')
SQS_QUEUE_URL = os.environ.get('SQS_QUEUE_URL', '')

def lambda_handler(event, context):
    """
    Example Lambda function demonstrating usage of shared IAM role permissions.
    This function can perform operations on S3, DynamoDB, SNS, and SQS.
    """
    try:
        response_data = {
            'statusCode': 200,
            'timestamp': datetime.utcnow().isoformat(),
            'operations': []
        }
        
        # Example S3 operation
        if event.get('s3_operation'):
            s3_key = event.get('s3_key', f"test-{datetime.utcnow().timestamp()}.json")
            s3_data = event.get('s3_data', {'message': 'Test data'})
            
            s3_client.put_object(
                Bucket=BUCKET_NAME,
                Key=s3_key,
                Body=json.dumps(s3_data),
                ContentType='application/json'
            )
            response_data['operations'].append(f'S3: Uploaded {s3_key}')
        
        # Example DynamoDB operation
        if event.get('dynamodb_operation'):
            table = dynamodb.Table(TABLE_NAME)
            item_id = event.get('item_id', f"item-{int(datetime.utcnow().timestamp())}")
            
            table.put_item(
                Item={
                    'id': item_id,
                    'data': event.get('item_data', {}),
                    'timestamp': datetime.utcnow().isoformat()
                }
            )
            response_data['operations'].append(f'DynamoDB: Created item {item_id}')
        
        # Example SNS operation
        if event.get('sns_operation') and SNS_TOPIC_ARN:
            message = event.get('sns_message', 'Test notification')
            
            sns_response = sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=json.dumps({
                    'default': message,
                    'timestamp': datetime.utcnow().isoformat()
                }),
                Subject='Microservice Notification',
                MessageStructure='json'
            )
            response_data['operations'].append(f'SNS: Published message {sns_response["MessageId"]}')
        
        # Example SQS operation
        if event.get('sqs_operation') and SQS_QUEUE_URL:
            message = event.get('sqs_message', 'Test queue message')
            
            sqs_response = sqs_client.send_message(
                QueueUrl=SQS_QUEUE_URL,
                MessageBody=json.dumps({
                    'message': message,
                    'timestamp': datetime.utcnow().isoformat()
                })
            )
            response_data['operations'].append(f'SQS: Sent message {sqs_response["MessageId"]}')
        
        # Example query operation
        if event.get('query_operation'):
            table = dynamodb.Table(TABLE_NAME)
            query_key = event.get('query_key', 'id')
            query_value = event.get('query_value')
            
            if query_value:
                db_response = table.get_item(Key={query_key: query_value})
                if 'Item' in db_response:
                    response_data['query_result'] = db_response['Item']
                    response_data['operations'].append(f'DynamoDB: Retrieved item {query_value}')
        
        return {
            'statusCode': 200,
            'body': json.dumps(response_data),
            'headers': {
                'Content-Type': 'application/json',
                'X-Function-Name': context.function_name if context else 'local'
            }
        }
        
    except Exception as e:
        error_response = {
            'statusCode': 500,
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }
        
        return {
            'statusCode': 500,
            'body': json.dumps(error_response),
            'headers': {
                'Content-Type': 'application/json'
            }
        }

def process_sqs_event(event, context):
    """
    Example Lambda function for processing SQS events.
    Uses the same shared IAM role.
    """
    records_processed = []
    
    for record in event.get('Records', []):
        message_body = json.loads(record['body'])
        
        # Store in DynamoDB
        table = dynamodb.Table(TABLE_NAME)
        table.put_item(
            Item={
                'id': record['messageId'],
                'data': message_body,
                'timestamp': datetime.utcnow().isoformat(),
                'source': 'SQS'
            }
        )
        
        # Archive to S3
        s3_client.put_object(
            Bucket=BUCKET_NAME,
            Key=f"sqs-messages/{record['messageId']}.json",
            Body=json.dumps(message_body)
        )
        
        records_processed.append(record['messageId'])
    
    return {
        'statusCode': 200,
        'body': json.dumps({
            'processed': len(records_processed),
            'messageIds': records_processed
        })
    }

def process_s3_event(event, context):
    """
    Example Lambda function for processing S3 events.
    Uses the same shared IAM role.
    """
    results = []
    
    for record in event.get('Records', []):
        bucket = record['s3']['bucket']['name']
        key = record['s3']['object']['key']
        
        # Read from S3
        obj = s3_client.get_object(Bucket=bucket, Key=key)
        content = json.loads(obj['Body'].read())
        
        # Store metadata in DynamoDB
        table = dynamodb.Table(TABLE_NAME)
        table.put_item(
            Item={
                'id': key,
                'bucket': bucket,
                'size': record['s3']['object']['size'],
                'timestamp': datetime.utcnow().isoformat(),
                'eventName': record['eventName']
            }
        )
        
        # Notify via SNS if configured
        if SNS_TOPIC_ARN:
            sns_client.publish(
                TopicArn=SNS_TOPIC_ARN,
                Message=json.dumps({
                    'event': 'S3ObjectProcessed',
                    'bucket': bucket,
                    'key': key
                }),
                Subject='S3 Object Processed'
            )
        
        results.append({'bucket': bucket, 'key': key, 'status': 'processed'})
    
    return {
        'statusCode': 200,
        'body': json.dumps({'results': results})
    }